CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_journal_detail() RETURNS trigger AS $BODY$
BEGIN
  ------------------------------------------------------------------------------
  if coalesce(NEW.FIN_SIGN::text, '') = '' then NEW.FIN_SIGN := '0';end if;
  if coalesce(trim(both NEW.FIN_BOOK)::text, '') = '' then NEW.FIN_BOOK := '0';end if;
  if coalesce(NEW.POSTTO_ACCOUNT::text, '') = '' or NEW.POSTTO_ACCOUNT <> '1' then NEW.POSTTO_ACCOUNT := '0';end if;
  ------------------------------------------------------------------------------
  if coalesce(NEW.ITEM_AMOUNT::text, '') = '' then NEW.ITEM_AMOUNT := 0;end if;

    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
        select max(seq_no) into STRICT NEW.seq_no 
        from sc_fin_journal_detail
        where branch_fin = NEW.branch_fin
        and journal_date = NEW.journal_date
        and entry_fin = NEW.entry_fin 
        and open_no = NEW.open_no
        and fin_book = NEW.fin_book;
        NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
    end if;

RETURN NEW;
end
